import{C as n,o as i,c as l,a5 as t,E as r}from"./chunks/framework.CW28V7p_.js";const d=JSON.parse('{"title":"3. Rent and rent-exempt","description":"","frontmatter":{},"headers":[],"relativePath":"module-2/3-rent.md","filePath":"module-2/3-rent.md","lastUpdated":1780937944000}'),o={name:"module-2/3-rent.md"},k=Object.assign(o,{setup(c){const s={id:"m2-3-rent",title:"🧠 Mini-check: Rent",intro:"3 питання щоб закріпити rent економіку.",questions:[{type:"mcq",q:"Що відбувається з account який НЕ має достатньо lamports для rent-exempt threshold?",options:["Account автоматично видаляється (garbage collected) при наступному epoch","Account залишається але не може приймати нові data","Cluster halts","Account paid rent кожну slot аж до закінчення lamports"],correct:[0],explanation:"Если account не rent-exempt і його lamports decrease below threshold — на наступному rent collection cycle account purged (видалений). Сучасно: всі нові accounts MUST be rent-exempt (мінімум lamports = rent threshold). Module 2.3."},{type:"command",q:"Як подивитись мінімум lamports для rent-exempt для account розміру 165 bytes (типовий token account)?",accepts:["solana rent 165","solana rent 165 --url mainnet-beta","sudo /home/solana/ag/bin/solana rent 165 --url http://localhost:8899"],ideal:"solana rent 165",explanation:"solana rent <SIZE_BYTES> виводить мінімум lamports потрібних щоб account такого розміру був rent-exempt. Для token account (165 bytes) на mainnet ~0.00203928 SOL. Module 2.3."},{type:"scenario",q:'Ти створюєш новий vote account з 1.000 SOL. Вотинг почався, але cluster повідомляє "stake account 1.00228 SOL requirement". Що сталось і як fix?',ideal:`Сталось: stake account requires rent reserve ПЛЮС достаточну lamports для considerити voting active. Rent-exempt threshold для stake account ~0.00228 SOL (приблизно). Тому мінімум: 0.00228 SOL rent reserve + amount you want to actually delegate.

Якщо ти hadn 1.000 SOL → effective delegated amount = 1.000 - 0.00228 = ~0.998. Воно ще можливо рабочe (~ ≥ 1 SOL для self-stake on Alpenglow), або не зовсім — залежить від cluster minimum.

Fix: transfer ще більше SOL у stake account (e.g., 2 SOL total). Тепер rent reserve + 1.998 active stake. Це і трапилось у твоєму Alpenglow case 2026-06-02 — додала 1 SOL більше, after that working.

OR: створити stake account з explicit amount > min:
solana create-stake-account stake-keypair.json 2 --from validator-keypair.json`,explanation:"Ключове: rent reserve деднує з effective stake amount. Якщо описала reserve + fix додати більше SOL — повна відповідь."}]};return(h,a)=>{const e=n("Quiz");return i(),l("div",null,[a[0]||(a[0]=t("",61)),r(e,{data:s}),a[1]||(a[1]=t("",6))])}}});export{d as __pageData,k as default};
